/**
 * Lightweight yt-dlp wrapper — truly plug-and-play.
 *
 * Handles the Alpine/musl Docker problem automatically:
 *   1. Downloads latest yt-dlp standalone binary
 *   2. If it fails (musl libc missing posix_fallocate64), writes a tiny
 *      pre-compiled shim library that maps posix_fallocate64 → posix_fallocate
 *   3. Runs yt-dlp with LD_PRELOAD for the shim — zero root access needed
 *
 * The shim is ~13KB (x86_64) / ~5KB (arm64), compiled on Alpine 3.20.
 * On 64-bit systems posix_fallocate64 and posix_fallocate are identical,
 * musl just doesn't export the "64" alias that Python 3.13 (used by
 * yt-dlp's PyInstaller build) expects.
 */

import { execFile, execFileSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import * as https from 'https';

// ── Constants ───────────────────────────────────────────────

const PACKAGE_ROOT = path.resolve(__dirname, '..', '..', '..');
const BIN_DIR = path.join(PACKAGE_ROOT, 'bin');
const RELEASE_URL = 'https://github.com/yt-dlp/yt-dlp/releases/latest/download';
const SHIM_FILENAME = 'libmuslfix.so';

// ── Embedded musl shim binaries ─────────────────────────────
// Compiled on Alpine 3.20 with:
//   gcc -shared -nostartfiles -O2 -s -o libmuslfix.so shim.c
// Source:
//   #include <fcntl.h>
//   int posix_fallocate64(int fd, off_t offset, off_t len) {
//       return posix_fallocate(fd, offset, len);
//   }

const MUSL_SHIM_X86_64 = '';

const MUSL_SHIM_AARCH64 = '';

// ── Candidate directories ───────────────────────────────────

function getCandidateDirs(): string[] {
  const dirs: string[] = [];
  dirs.push(BIN_DIR);
  const n8nDir = process.env.N8N_USER_FOLDER || path.join(os.homedir(), '.n8n');
  dirs.push(path.join(n8nDir, 'ytdlp'));
  dirs.push(path.join(os.homedir(), '.local', 'bin'));
  dirs.push(path.join(os.tmpdir(), 'ytdlp'));
  return dirs;
}

// ── Platform detection ──────────────────────────────────────

/** Detect musl libc — checks dynamic linker, /etc/alpine-release, and ldd */
function detectMusl(): boolean {
  if (process.platform !== 'linux') return false;

  // Check for musl dynamic linker (most reliable)
  try {
    const libs = fs.readdirSync('/lib');
    if (libs.some(f => f.startsWith('ld-musl-'))) return true;
  } catch { /* ignore */ }

  // Check /etc/alpine-release
  try { if (fs.existsSync('/etc/alpine-release')) return true; } catch { /* ignore */ }

  // Check ldd output
  try {
    const out = execFileSync('ldd', ['--version'], {
      timeout: 5_000, encoding: 'utf-8', stdio: ['ignore', 'pipe', 'pipe'],
    });
    if (out.toLowerCase().includes('musl')) return true;
  } catch (e: any) {
    const stderr = e?.stderr?.toString() || '';
    if (stderr.toLowerCase().includes('musl')) return true;
  }

  return false;
}

function hasCurl(): boolean {
  try { execFileSync('curl', ['--version'], { timeout: 5_000, stdio: 'ignore' }); return true; } catch { return false; }
}

function hasWget(): boolean {
  try { execFileSync('wget', ['--version'], { timeout: 5_000, stdio: 'ignore' }); return true; } catch { return false; }
}

function getStandaloneName(): string | null {
  const p = process.platform;
  const a = process.arch;
  if (p === 'linux') return a === 'arm64' ? 'yt-dlp_linux_aarch64' : 'yt-dlp_linux';
  if (p === 'darwin') return 'yt-dlp_macos';
  if (p === 'win32') return 'yt-dlp.exe';
  return null;
}

function binaryFilename(): string {
  return process.platform === 'win32' ? 'yt-dlp.exe' : 'yt-dlp';
}

// ── Directory helpers ───────────────────────────────────────

function isWritableDir(dir: string): boolean {
  try {
    fs.mkdirSync(dir, { recursive: true });
    const t = path.join(dir, '.write-test-' + process.pid);
    fs.writeFileSync(t, 'ok');
    fs.unlinkSync(t);
    return true;
  } catch { return false; }
}

// ── Download methods ────────────────────────────────────────

function downloadWithCurl(url: string, dest: string): void {
  execFileSync('curl', ['-fsSL', '--connect-timeout', '30', '-o', dest, url], {
    timeout: 120_000, stdio: ['ignore', 'ignore', 'pipe'],
  });
}

function downloadWithWget(url: string, dest: string): void {
  execFileSync('wget', ['-q', '-O', dest, url], {
    timeout: 120_000, stdio: ['ignore', 'ignore', 'pipe'],
  });
}

function downloadWithHttps(url: string): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    const request = (u: string, redirects = 0) => {
      if (redirects > 10) { reject(new Error('Too many redirects')); return; }
      https.get(u, { headers: { 'User-Agent': 'n8n-nodes-youtube-dl/2.x' } }, (res) => {
        if (res.statusCode && res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
          request(res.headers.location, redirects + 1); return;
        }
        if (!res.statusCode || res.statusCode >= 400) {
          reject(new Error(`HTTP ${res.statusCode}`)); return;
        }
        const chunks: Buffer[] = [];
        res.on('data', (c: Buffer) => chunks.push(c));
        res.on('end', () => resolve(Buffer.concat(chunks)));
        res.on('error', reject);
      }).on('error', reject);
    };
    request(url);
  });
}

async function downloadFile(url: string, dest: string): Promise<{ ok: true } | { ok: false; errors: string[] }> {
  const errors: string[] = [];

  if (hasCurl()) {
    try {
      downloadWithCurl(url, dest);
      if (fs.existsSync(dest) && fs.statSync(dest).size > 0) return { ok: true };
      errors.push('curl: file empty');
    } catch (e: any) {
      errors.push(`curl: ${(e?.stderr?.toString() || e?.message || '').trim().slice(0, 120)}`);
    }
  } else { errors.push('curl: N/A'); }

  if (hasWget()) {
    try {
      downloadWithWget(url, dest);
      if (fs.existsSync(dest) && fs.statSync(dest).size > 0) return { ok: true };
      errors.push('wget: file empty');
    } catch (e: any) {
      errors.push(`wget: ${(e?.stderr?.toString() || e?.message || '').trim().slice(0, 120)}`);
    }
  } else { errors.push('wget: N/A'); }

  try {
    const buffer = await downloadWithHttps(url);
    if (buffer.length > 0) { fs.writeFileSync(dest, buffer); return { ok: true }; }
    errors.push('https: buffer empty');
  } catch (e: any) {
    errors.push(`https: ${(e?.message || '').trim().slice(0, 120)}`);
  }

  return { ok: false, errors };
}

// ── Binary testing (with optional LD_PRELOAD) ───────────────

function testBinary(binPath: string, env?: Record<string, string>): { ok: boolean; error?: string } {
  try {
    const out = execFileSync(binPath, ['--version'], {
      timeout: 15_000, encoding: 'utf-8',
      stdio: ['ignore', 'pipe', 'pipe'],
      env: env || process.env,
    });
    if (out.trim().length > 0) return { ok: true };
    return { ok: false, error: 'Empty version output' };
  } catch (e: any) {
    const msg = e?.stderr?.toString()?.trim() || e?.message || String(e);
    return { ok: false, error: msg.slice(0, 200) };
  }
}

function isMuslError(error: string, binPath?: string): boolean {
  // Symbol resolution errors (x86_64 musl — binary starts but dlopen fails)
  if (error.includes('posix_fallocate64') ||
    error.includes('symbol not found') ||
    error.includes('Error relocating') ||
    error.includes('GLIBC') ||
    error.includes('libpython')) return true;

  // ENOENT when the file exists → ELF interpreter missing (ARM64 musl)
  if (binPath && error.includes('ENOENT') && fs.existsSync(binPath)) return true;

  return false;
}

// ── Musl shim installer ─────────────────────────────────────

/**
 * Write the embedded musl shim to disk. The shim provides
 * posix_fallocate64 → posix_fallocate so yt-dlp's PyInstaller
 * binary works on musl/Alpine without root or gcompat.
 */
function installMuslShim(baseDir: string, diagnostics: string[]): string | null {
  const shimPath = path.join(baseDir, SHIM_FILENAME);

  // Already installed?
  if (fs.existsSync(shimPath)) {
    try {
      const stat = fs.statSync(shimPath);
      if (stat.size > 0) return shimPath;
    } catch { /* re-create */ }
  }

  // Pick the right shim for the architecture
  const arch = process.arch;
  let shimBase64: string;
  if (arch === 'x64') {
    shimBase64 = MUSL_SHIM_X86_64;
    diagnostics.push('[shim: using x86_64 variant]');
  } else if (arch === 'arm64') {
    shimBase64 = MUSL_SHIM_AARCH64;
    diagnostics.push('[shim: using aarch64 variant]');
  } else {
    diagnostics.push(`[shim: no variant for arch ${arch}]`);
    return null;
  }

  // Ensure directory is writable
  if (!isWritableDir(baseDir)) {
    diagnostics.push(`[shim: ${baseDir} not writable]`);
    return null;
  }

  try {
    const buffer = Buffer.from(shimBase64, 'base64');
    fs.writeFileSync(shimPath, buffer, { mode: 0o755 });
    diagnostics.push(`[shim: wrote ${buffer.length} bytes to ${shimPath}]`);
    return shimPath;
  } catch (e: any) {
    diagnostics.push(`[shim write error: ${(e?.message || '').slice(0, 80)}]`);
    return null;
  }
}

/** Build the env object for running yt-dlp with the musl shim */
function buildShimEnv(shimPath: string): Record<string, string> {
  const env = { ...process.env } as Record<string, string>;
  env.LD_PRELOAD = shimPath + (env.LD_PRELOAD ? `:${env.LD_PRELOAD}` : '');
  return env;
}

// ── Find existing binary ────────────────────────────────────

function findExistingBinary(): { bin: string; shimPath?: string } | null {
  const fname = binaryFilename();

  // Helper: try to run a binary, optionally with musl shim
  const tryBin = (p: string): { bin: string; shimPath?: string } | null => {
    // Direct
    if (testBinary(p).ok) return { bin: p };

    // With existing shim in candidate dirs
    for (const dir of getCandidateDirs()) {
      const shim = path.join(dir, SHIM_FILENAME);
      if (fs.existsSync(shim) && testBinary(p, buildShimEnv(shim)).ok) {
        return { bin: p, shimPath: shim };
      }
    }
    return null;
  };

  // 1. Environment variable
  if (process.env.YT_DLP_PATH && fs.existsSync(process.env.YT_DLP_PATH)) {
    const result = tryBin(process.env.YT_DLP_PATH);
    if (result) return result;
  }

  // 2. Candidate directories — standalone binary
  for (const dir of getCandidateDirs()) {
    const p = path.join(dir, fname);
    if (!fs.existsSync(p)) continue;
    const result = tryBin(p);
    if (result) return result;
  }

  // 3. System yt-dlp on PATH
  if (testBinary('yt-dlp').ok) return { bin: 'yt-dlp' };

  return null;
}

// ── Main download + setup logic ─────────────────────────────

async function downloadAndSetup(): Promise<{ bin: string; shimPath?: string }> {
  const fname = binaryFilename();
  const musl = detectMusl();
  const diagnostics: string[] = [];

  diagnostics.push(`[env: ${process.platform}/${process.arch}${musl ? ' musl' : ''}]`);

  const standaloneName = getStandaloneName();
  if (!standaloneName) {
    throw new Error(`Unsupported platform: ${process.platform}/${process.arch}`);
  }

  const url = `${RELEASE_URL}/${standaloneName}`;

  // Download yt-dlp binary to first viable directory
  for (const dir of getCandidateDirs()) {
    if (!isWritableDir(dir)) { diagnostics.push(`[${dir}: not writable]`); continue; }

    const dest = path.join(dir, fname);
    diagnostics.push(`[downloading to ${dir}]`);

    const dlResult = await downloadFile(url, dest);
    if (!dlResult.ok) {
      diagnostics.push(`[download failed: ${dlResult.errors.join('; ')}]`);
      continue;
    }

    if (process.platform !== 'win32') {
      try { fs.chmodSync(dest, 0o755); } catch { /* ignore */ }
    }

    // Test the binary directly
    const directTest = testBinary(dest);
    if (directTest.ok) {
      return { bin: dest };
    }

    diagnostics.push(`[direct test failed: ${directTest.error}]`);

    // If musl error → install the embedded shim
    if (isMuslError(directTest.error || '', dest)) {
      diagnostics.push('[musl incompatibility detected — installing embedded shim]');

      // Try writing shim to same dir first, then other candidate dirs
      for (const shimBaseDir of getCandidateDirs()) {
        const shimPath = installMuslShim(shimBaseDir, diagnostics);
        if (!shimPath) continue;

        const shimTest = testBinary(dest, buildShimEnv(shimPath));
        if (shimTest.ok) {
          diagnostics.push(`[✓ yt-dlp works with musl shim LD_PRELOAD from ${shimBaseDir}]`);
          return { bin: dest, shimPath };
        }
        diagnostics.push(`[shim test failed: ${shimTest.error}]`);
      }
    } else {
      try { fs.unlinkSync(dest); } catch { /* ignore */ }
    }
  }

  // ── All strategies failed ─────────────────────────────────
  let msg = 'yt-dlp could not be set up automatically.\n\n';
  msg += `Platform: ${process.platform}/${process.arch}`;
  if (musl) msg += ' (musl/Alpine)';
  msg += '\n\nDiagnostics:\n' + diagnostics.join('\n') + '\n\n';
  msg += '══ HOW TO FIX ══\n';
  msg += '  Option 1: Install yt-dlp system-wide → https://github.com/yt-dlp/yt-dlp#installation\n';
  msg += '  Option 2: Set YT_DLP_PATH=/path/to/working/yt-dlp\n';
  msg += '  Option 3: Use a Dockerfile with gcompat:\n';
  msg += '    FROM n8nio/n8n:latest\n';
  msg += '    USER root\n';
  msg += '    RUN apk add --no-cache gcompat\n';
  msg += '    USER node\n';

  throw new Error(msg);
}

// ── Cached state ────────────────────────────────────────────

let cachedBinary: string | null = null;
let cachedShimPath: string | undefined;
let ensurePromise: Promise<void> | null = null;

export async function ensureBinary(): Promise<string> {
  if (cachedBinary) return cachedBinary;

  if (!ensurePromise) {
    ensurePromise = (async () => {
      // Check for existing working binary first
      const existing = findExistingBinary();
      if (existing) {
        cachedBinary = existing.bin;
        cachedShimPath = existing.shimPath;
        return;
      }

      // Download and set up
      const result = await downloadAndSetup();
      cachedBinary = result.bin;
      cachedShimPath = result.shimPath;
    })();
  }

  await ensurePromise;
  return cachedBinary!;
}

// ── Core executor ───────────────────────────────────────────

export interface ExecResult {
  stdout: string;
  stderr: string;
}

export function runYtDlp(
  bin: string,
  args: string[],
  timeoutMs = 300_000,
): Promise<ExecResult> {
  return new Promise((resolve, reject) => {
    const env = cachedShimPath ? buildShimEnv(cachedShimPath) : process.env;

    execFile(
      bin,
      args,
      {
        maxBuffer: 100 * 1024 * 1024,
        timeout: timeoutMs,
        windowsHide: true,
        env,
      },
      (error, stdout, stderr) => {
        if (error) {
          const msg = stderr?.trim() || error.message;
          reject(new Error(msg));
          return;
        }
        resolve({ stdout: stdout || '', stderr: stderr || '' });
      },
    );
  });
}

// ── Typed helpers ───────────────────────────────────────────

export async function getInfo(url: string, extraFlags: string[] = []): Promise<any> {
  const bin = await ensureBinary();
  const { stdout } = await runYtDlp(bin, [
    '--dump-single-json',
    '--no-download',
    '--no-check-certificates',
    '--no-warnings',
    ...extraFlags,
    url,
  ]);
  return JSON.parse(stdout);
}

export async function download(
  url: string,
  outputTemplate: string,
  extraFlags: string[] = [],
  timeoutMs = 600_000,
): Promise<void> {
  const bin = await ensureBinary();
  await runYtDlp(
    bin,
    [
      '--no-check-certificates',
      '--no-warnings',
      '-o',
      outputTemplate,
      ...extraFlags,
      url,
    ],
    timeoutMs,
  );
}
